use strict;
open(F, "<", "/app/gpt2-124M.ckpt") or die;
binmode F;
read(F, my $buf, 64);
close F;

# Decode first 8 bytes as float32 (little-endian)
my @floats;
for my $i (0..7) {
    my ($b0,$b1,$b2,$b3) = (ord(substr($buf,$i*4,1)), ord(substr($buf,$i*4+1,1)), ord(substr($buf,$i*4+2,1)), ord(substr($buf,$i*4+3,1)));
    my $bits = ($b3 << 24) | ($b2 << 16) | ($b1 << 8) | $b0;
    # Manual float decode
    my $sign = ($bits >> 31) & 1;
    my $exp = (($bits >> 23) & 0xFF) - 127;
    my $mantissa = ($bits & 0x7FFFFF) | 0x800000;
    my $val = ($sign ? -1 : 1) * ($mantissa / (1 << 23)) * (2 ** $exp);
    push @floats, $val;
}
print "First 8 float32 values: ", join(", ", map { sprintf("%.6f", $_) } @floats), "\n";

# Check if first value could be a header/version
# 0x3eef5ef0 as float... bytes are 03 f5 ef 3e
# LE uint32 = 0x3ef5f503... no
# Let me try: the raw bytes 03 f5 ef 3e
# As LE float: interpret as IEEE754
my $raw = unpack("V", substr($buf, 0, 4));
print "Raw uint32 of first 4 bytes: 0x" . sprintf("%08x", $raw) . "\n";

# Actually in LE, the bytes are stored as-is, so:
# float32 at offset 0: bytes [03 f5 ef 3e] 
# In memory (LE), this represents the float whose binary is 3e ef f5 03
my $bits = unpack("V", substr($buf, 0, 4));
print "Bits: 0x" . sprintf("%08x", $bits) . "\n";
'"}

