# Parse as float32 LE
sub read_f32 {
    my ($data, $off) = @_;
    my ($b0,$b1,$b2,$b3) = (ord(substr($data,$off,1)), ord(substr($data,$off+1,1)), ord(substr($data,$off+2,1)), ord(substr($data,$off+3,1)));
    my $bits = ($b3 << 24) | ($b2 << 16) | ($b1 << 8) | $b0;
    my $sign = ($bits >> 31) & 1;
    my $exp = (($bits >> 23) & 0xFF) - 127;
    my $mantissa = ($bits & 0x7FFFFF) / (1 << 23);
    my $val;
    if ($exp == -127 && $mantissa == 0) {
        $val = 0.0;
    } else {
        $val = ($sign ? -1 : 1) * (1 + $mantissa) * (2 ** $exp);
    }
    return $val;
}

# Print first 20 floats
for my $i (0..19) {
    printf "%.8f\n", read_f32($buf, $i*4);
}
print "\n";

# Check range of first 50257*768 values (embedding)
