binmode F;
read(F, $buf, 50257 * 768 * 4);
close F;

my ($min, $max) = (1e9, -1e9);
for my $i (0..(50257*768)-1) {
    my $v = read_f32($buf, $i*4);
    $min = $v if $v < $min;
    $max = $v if $v > $max;
}
