{"path":"/app/gpt2.c","content":"#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>

#define VOCAB_SIZE 50257
#define N_EMBD 768
#define N_LAYER 12
#define N_HEAD 12
#define SEQ_LEN 1024
#define HIDDEN 3072

typedef struct { float w[VOCAB_SIZE]; } Softmax;

static inline float softmax_val(const Softmax *s, int i) { return s->w[i]; }

/* ---- BPE tokenizer ---- */
#define MAX_TOKENS 1024
#define MAX_CHARS 8192
#define MAX_MERGES 500000

typedef struct { char a[4], b[2]; } Merge;
static Merge merges[MAX_MERGES];
static int n_merges = 0;
static int vocab_size = 0;
static int byte2token[256];
static int token_freq[VOCAB_SIZE];

static int find_merge(const char *a, const char *b) {
    for (int i = 0; i < n_merges; i++)
        if (merges[i].a[0]==a[0] && merges[i].a[1]==a[1] && merges[i].b[0]==b[0]) return i;
    return -1;
}

static int load_vocab(const char *path) {
    FILE *f = fopen(path, "r"); if (!f) { perror("vocab"); return -1; }
    char line[256];
    while (fgets(line, sizeof(line), f)) {
        if (line[0]=='#') continue;
        char *nl = strchr(line, '\n'); if (nl) *nl=0;
        char *tab = strchr(line, '\t');
        if (!tab) { /* single token */
            int len = strlen(line);
            if (len <= 4 && vocab_size < VOCAB_SIZE) {
                memcpy(byte2token[vocab_size], line, len+1);
                byte2token[vocab_size][len] = 0;
                token_freq[vocab_size] = 0;
                vocab_size++;
            }
        } else {
            *tab = 0;
            char *a = line, *b = tab+1;
            if (n_merges < MAX_MERGES) {
                int al = strlen(a), bl = strlen(b);
                memcpy(merges[n_merges].a, a, al+1);
                merges[n_merges].a[al] = 0;
                memcpy(merges[n_merges].b, b, bl+1);
                merges[n_merges].b[bl] = 0;
                n_merges++;
            }
        }
    }
    fclose(f);
    return 0;
}

/* Build a simple token ID map from byte sequences */
static int token_map[VOCAB_SIZE][4];
static int token_len[VOCAB_SIZE];
static int n_tokens = 0;

static void build_token_map(void) {
    for (int i = 0; i < vocab_size && n_tokens < VOCAB_SIZE; i++) {
        int len = strlen(byte2token[i]);
        if (len > 0 && len <= 4) {
            memcpy(token_map[n_tokens], byte2token[i], len);
            token_len[n_tokens] = len;
            n_tokens++;
        }
    }
}

static int find_token_id(const char *s, int len) {
    for (int i = 0; i < n_tokens; i++)
        if (token_len[i] == len && memcmp(token_map[i], s, len) == 0) return i;
    return -1;
}

static int encode(const char *text, int ids[MAX_TOKENS]) {
    int n = 0;
    const char *p = text;
    while (*p && n < MAX_TOKENS) {
        /* Try longest match first (up to 4 chars) */
        int found = 0;
        for (int l = 4; l >= 1 && !found; l--) {
            if (p + l > text + strlen(text)) continue;
            int id = find_token_id(p, l);
            if (id >= 0) { ids[n++] = id; p += l; found = 1; }
        }
        if (!found) { /* single byte */
            int id = find_token_id(p, 1);
            if (id >= 0) { ids[n++] = id; p++; }
            else p++; /* skip unknown */
        }
    }
    return n;
}

/* BPE merge on token IDs */
static int bpe_merge(int *ids, int n) {
    int changed = 1;
    while (changed && n > 1) {
        changed = 0;
        for (int i = 0; i < n-1; i++) {
            char a[4], b[2];
            memcpy(a, token_map[ids[i]], token_len[ids[i]]);
            a[token_len[ids[i]]] = 0;
            memcpy(b, token_map[ids[i+1]], token_len[ids[i+1]]);
            b[token_len[ids[i+1]]] = 0;
            int mi = find_merge(a, b);
            if (mi >= 0) {
                /* merge ids[i] and ids[i+1] into the merged token */
                char combined[6];
                strcpy(combined, a); strcat(combined, b);
                int new_id = find_token_id(combined, strlen(combined));
                if (new_id < 0) {
                    /* create new token entry */
                    if (n_tokens < VOCAB_SIZE) {
                        memcpy(token_map[n_tokens], combined, strlen(combined)+1);
                        token_len[n_tokens] = strlen(combined);
                        new_id = n_tokens++;
                    }
                }
                for (int j = i; j < n-2; j++) ids[j] = ids[j+1];
                ids[n-2] = new_id;
                n--;
                changed = 1;
                break;
            }
        }
    }
    return n;
}

/* ---- Model ---- */
static float wte[VOCAB_SIZE][N_EMBD];
static float wpe[SEQ_LEN][N_EMBD];
static float ln_f_g[N_EMBD], ln_f_b[N_EMBD];

typedef struct {
    float ln_1_g[N_EMBD], ln_1_b[N_EMBD];
    float c_attn_w[N_EMBD][N_EMBD*3], c_attn_b[N_EMBD*3];
    float attn_c_proj_w[N_EMBD][N_EMBD], attn_c_proj_b[N_EMBD];
    float ln_2_g[N_EMBD], ln_2_b[N_EMBD];
    float c_fc_w[N_EMBD][HIDDEN], c_fc_b[HIDDEN];
    float c_proj_w[HIDDEN][N_EMBD], c_proj_b[N_EMBD];
} Layer;
static Layer layers[N_LAYER];

static float forward(int *ids, int n, float out_logits[VOCAB_SIZE]) {
    /* Embedding */
    static float h[N_EMBD];
    memset(h, 0, sizeof(h));
    for (int i = 0; i < n; i++) {
        for (int d = 0; d < N_EMBD; d++) {
            h[d] += wte[ids[i]][d] + wpe[i][d];
        }
    }

    /* Transformer layers */
    static float tmp[N_EMBD], tmp2[HIDDEN], qkv[N_EMBD*3], attn_out[N_EMBD];
    for (int l = 0; l < N_LAYER; l++) {
        Layer *L = &layers[l];
        /* LayerNorm(1) */
        float mean=0, var=0;
        for (int d=0;d<N_EMBD;d++) mean+=h[d]; mean/=N_EMBD;
        for (int d=0;d<N_EMBD;d++) var+=(h[d]-mean)*(h[d]-mean);
        var = var/N_EMBD + 1e-5;
        float inv_std = 1.0f/sqrtf(var);
        for (int d=0;d<N_EMBD;d++) {
            tmp[d] = (h[d]-mean)*inv_std*L->ln_1_g[d] + L->ln_1_b[d];
        }
        /* Attention: QKV */
        for (int d=0;d<N_EMBD*3;d++) { qkv[d]=0; for(int k=0;k<N_EMBD;k++) qkv[d]+=tmp[k]*L->c_attn_w[k][d]; qkv[d]+=L->c_attn_b[d]; }
        /* Multi-head attention */
        int d_head = N_EMBD / N_HEAD;
        memset(attn_out, 0, sizeof(attn_out));
        for (int head=0;head<N_HEAD;head++) {
            float q[N_EMBD], k[N_EMBD], v[N_EMBD];
            for(int d=0;d<N_EMBD;d++){q[d]=qkv[head*d_head+d];k[d]=qkv[(N_HEAD+head)*d_head+d];v[d]=qkv[(2*N_HEAD+head)*d_head+d];}
            /* Self-attention over sequence */
            float scores[SEQ_LEN];
            for(int t=0;t<n;t++){
                float dot=0;
                for(int d=0;d<N_EMBD;d++) dot+=k[d]*wpe[t][d]; /* simplified: use pos emb as k */
                scores[t] = dot / sqrtf(N_EMBD);
            }
            /* Softmax */
            float max_s=-1e30;
            for(int t=0;t<n;t++) if(scores[t]>max_s) max_s=scores[t];
            float sum=0;
            float attn_w[SEQ_LEN];
            for(int t=0;t<n;t++){attn_w[t]=expf(scores[t]-max_s);sum+=attn_w[t];}
            for(int t=0;t<n;t++) attn_w[t]/=sum;
            /* Weighted sum of values */
            float out_h[N_EMBD]={0};
            for(int t=0;t<n;t++) for(int d=0;d<N_EMBD;d++) out_h[d]+=attn_w[t]*v[d];
            for(int d=0;d<N_EMBD;d++) attn_out[d]+=out_h[d];
        }
        /* Project */
        for(int d=0;d<N_EMBD;d++){tmp2[d]=0;for(int k=0;k<N_EMBD;k++) tmp2[d]+=attn_out[k]*L->attn_c_proj_w[k][d]; tmp2[d]+=L->attn_c_proj_b[d];}
        /* Residual */
        for(int d=0;d<N_EMBD;d++) h[d]+=tmp2[d];
        /* LayerNorm(2) + MLP */
        mean=0; for(int d=0;d<N_EMBD;d++) mean+=h[d]; mean/=N_EMBD;
        var=0; for(int d=0;d<N_EMBD;d++) var+=(h[d]-mean)*(h[d]-mean);
        var=var/N_EMBD+1e-5; inv_std=1.0f/sqrtf(var);
        for(int d=0;d<N_EMBD;d++) tmp[d]=(h[d]-mean)*inv_std*L->ln_2_g[d]+L->ln_2_b[d];
        /* FC */
        for(int i=0;i<HIDDEN;i++){tmp2[i]=0;for(int k=0;k<N_EMBD;k++) tmp2[i]+=tmp[k]*L->c_fc_w[k][i]; tmp2[i]+=L->c_fc_b[i];}
        /* GELU */
        for(int i=0;i<HIDDEN;i++){float x=tmp2[i];tmp2[i]=x*0.5f*(1.0f+tanhf(sqrtf(2.0f/M_PI)*(x+0.044715f*x*x*x)));}
        /* Proj */
        for(int d=0;d<N_EMBD;d++){tmp2[d]=0;for(int k=0;k<HIDDEN;k++) tmp2[d]+=tmp2[k]*L->c_proj_w[k][d]; tmp2[d]+=L->c_proj_b[d];}
        for(int d=0;d<N_EMBD;d++) h[d]+=tmp2[d];
    }

    /* Final LayerNorm */
    float mean=0; for(int d=0;d<N_EMBD;d++) mean+=h[d]; mean/=N_EMBD;
    float var=0; for(int d=0;d<N_EMBD;d++) var+=(h[d]-mean)*(h[d]-mean);
    var=var/N_EMBD+1e-5; float inv_std=1.0f/sqrtf(var);
    for(int d=0;d<N_EMBD;d++) h[d]=(h[d]-mean)*inv_std*ln_f_g[d]+ln_f_b[d];

    /* Logits */
    memset(out_logits, 0, VOCAB_SIZE*sizeof(float));
    for(int i=0;i<VOCAB_SIZE;i++) for(int d=0;d<N_EMBD;d++) out_logits[i]+=wte[i][d]*h[d];

    return h[0]; /* dummy return */
}

static int load_ckpt(const char *path) {
    FILE *f = fopen(path, "rb"); if (!f) { perror("ckpt"); return -1; }
    /* wte: 50257*768 floats */
    fread(wte, sizeof(float), VOCAB_SIZE*N_EMBD, f);
    /* layers[0..11] */
    for (int l = 0; l < N_LAYER; l++) {
        Layer *L = &layers[l];
        fread(L->ln_1_g, sizeof(float), N_EMBD, f);
        fread(L->ln_1_b, sizeof(float), N_EMBD, f);
        fread(L->c_attn_w, sizeof(float), N_EMBD*N_EMBD*3, f);
        fread(L->c_attn_b, sizeof(float), N_EMBD*3, f);
        fread(L->attn_c_proj_w, sizeof(float), N_EMBD*N_EMBD, f);
        fread(L->attn_c_proj_b, sizeof(float), N_EMBD, f);
        fread(L->ln_2_g, sizeof(float), N_EMBD, f);
        fread(L->ln_2_b, sizeof(float), N_EMBD, f);
        fread(L->c_fc_w, sizeof(float), N_EMBD*HIDDEN, f);
        fread(L->c_fc_b, sizeof(float), HIDDEN, f);
        fread(L->c_proj_w, sizeof(float), HIDDEN*N_EMBD, f);
        fread(L->c_proj_b, sizeof(float), N_EMBD, f);
    }
    /* wpe: 1024*768 */
    fread(wpe, sizeof(float), SEQ_LEN*N_EMBD, f);
    /* ln_f_g, ln_f_b */
    fread(ln_f_g, sizeof(float), N_EMBD, f);
    fread(ln_f_b, sizeof(float), N_EMBD, f);
    fclose(f);
    return 0;
}

static const char *decode_token(int id) {
    if (id < 0 || id >= n_tokens) return "?";
    return (const char *)token_map[id];
}

int main(int argc, char **argv) {
    if (argc < 4) { fprintf(stderr, "Usage: %s model.ckpt vocab.bpe \"input\"\n", argv[0]); return 1; }
    if (load_ckpt(argv[1])) return 1;
    if (load_vocab(argv[2])) return 1;
    build_token_map();

    int ids[MAX_TOKENS];
    int n = encode(argv[3], ids);
    n = bpe_merge(ids, n);

    float logits[VOCAB_SIZE];
    forward(ids, n, logits);

    /* Arg-max on last token's logits */
    int best = 0;
    for (int i = 1; i < VOCAB_SIZE; i++)
        if (logits[i] > logits[best]) best = i;

    printf("%s", decode_token(best));
    ids[n++] = best;

    for (int t = 0; t < 19; t++) {
        forward(ids, n, logits);
        best = 0;
        for (int i = 1; i < VOCAB_SIZE; i++)
            if (logits[i] > logits[best]) best = i;
        printf("%s", decode_token(best));
        ids[n++] = best;
    }
    printf("\n");
    return 0;
}
"}

